INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Live In Play commentary$q$, $q$Continuously updated notes on stocks moving on news, earnings, or unusual volume throughout the trading day.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Technical and fundamental analysis$q$, $q$Human-written analysis grounded in price action and company fundamentals rather than speculation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Earnings and news coverage$q$, $q$Real-time flagging of corporate earnings releases, guidance changes, and analyst rating actions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Broker platform integration$q$, $q$Commentary feeds embedded directly into third-party trading platforms such as Interactive Brokers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Sector and thematic coverage$q$, $q$Dedicated commentary on growth, momentum, value, and yield stocks as well as ETFs, options, and IPOs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Market recap archive$q$, $q$A free, publicly accessible archive of daily stock market recaps and commentary.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Over three decades of continuous operation and a consistent, disclosed analytical methodology$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Frequent intraday updates that track fast-moving news and price action in real time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Available directly and embedded inside popular brokerage platforms like Interactive Brokers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Tiered pricing lets casual investors and active professional traders choose an appropriate depth of coverage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Pricing and plan details are not consistently published on the main site, requiring a trial sign-up to see current rates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$No free ongoing tier beyond a trial and the limited public market recap section$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Aimed primarily at US equity markets, with less emphasis on international or crypto assets$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Human-written commentary format means less structured/API-friendly data than modern fintech data feeds$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$What is Briefing.com?$q$, $q$Briefing.com is a subscription-based stock market analysis service, founded in 1993, that provides live commentary on US equities, earnings, and market-moving news throughout the trading day.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$How much does Briefing.com cost?$q$, $q$Pricing is tiered: Briefing In Play is about $50/month, Briefing In Play Plus is about $75/month, and Briefing Trader is about $300/month, each with a discounted annual option.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Is there a free version of Briefing.com?$q$, $q$Briefing.com publishes a free public 'Stock Market Today' recap section, and each paid tier offers a free trial, but ongoing full access requires a paid subscription.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Can I access Briefing.com through my broker?$q$, $q$Yes. Briefing.com's commentary is integrated into several brokerage platforms, most notably Interactive Brokers, allowing subscribers to view it inside their trading interface.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Who is Briefing.com built for?$q$, $q$It is designed for self-directed retail investors, active day traders, and financial professionals who want fast, independent market commentary during trading hours.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Intraday trading decisions$q$, $q$Active traders use Briefing In Play or Briefing Trader to track which stocks are moving on news in real time and react quickly.$q$, $q$Active and day traders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Long-term investment research$q$, $q$Investors use Briefing.com's fundamental and technical commentary to inform buy/sell decisions on growth, value, and yield stocks.$q$, $q$Self-directed retail investors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$In-platform market context$q$, $q$Brokerage users view Briefing.com commentary directly inside platforms like Interactive Brokers without switching tools.$q$, $q$Brokerage platform users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Briefing In Play$q$, $q$$50/month or $480/year$q$, $q$Monthly or annual$q$, NULL, $q$["Live stock and sector commentary","Intraday updates","News and earnings tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Briefing In Play Plus$q$, $q$$75/month or $720/year$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in In Play","Deeper technical and fundamental analysis","Expanded market coverage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$Briefing Trader$q$, $q$$300/month or $3,300/year$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in In Play Plus","Trade-idea commentary","Coverage aimed at active professional traders"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Briefing.com was founded in 1993 by Dick Green in Chicago and was one of the first services to deliver live stock market analysis over the internet. For more than 30 years it has provided independent, data-driven commentary on US and international equity markets to individual investors and traders.$q$, $q$The service is built around continuous, human-written intraday commentary rather than automated headlines, covering stocks-in-play, earnings reactions, analyst rating changes, economic releases, and sector trends throughout the trading session.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Briefing.com's core product is live, frequently updated market commentary that tracks which stocks are 'in play' due to news, earnings, or unusual volume, paired with technical and fundamental context for each move.$q$, $q$The service also covers broader market themes such as growth and momentum stocks, yield and value ideas, IPOs, ETFs, options, and futures, and its commentary feed is integrated directly into brokerage platforms like Interactive Brokers so traders can view it without leaving their trading screen.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Briefing.com sells three subscription tiers rather than a single plan. Briefing In Play starts at roughly $50 per month (or $480 billed annually) and covers real-time stock and sector commentary.$q$, $q$Briefing In Play Plus adds deeper analysis for around $75 per month ($720 annually), while Briefing Trader, aimed at active professional traders, runs about $300 per month ($3,300 annually). Free trials are available for each tier, and a limited set of market recaps is published free on the public site.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53194735-82e1-4a27-b2dc-b4ed0454db1e', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Local rank tracking$q$, $q$Track local search rankings for up to 100 keywords and 4 competitors with geo-grid visualization.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Citation building and tracking$q$, $q$Build and monitor business listings (citations) across directories to improve local search consistency.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Google Business Profile tools$q$, $q$Audit GBP listings, schedule posts, and sync accurate business data automatically with Active Sync.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Review generation and monitoring$q$, $q$Automate customer review requests and monitor reviews across Google and other major platforms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Review showcase widget$q$, $q$Embed a widget on client or business websites to display collected reviews.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$White-label agency reporting$q$, $q$Generate branded reports for agencies managing local SEO on behalf of multiple clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Local SEO API$q$, $q$Programmatic access to BrightLocal's citation and ranking data for larger platforms and developers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Deep, purpose-built toolset specifically for local SEO rather than a generic SEO suite$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Agency-friendly white-label reporting and multi-client management$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Long operating history (founded 2008) as a stable, bootstrapped company$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Flexible options ranging from self-serve software to fully managed services$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Full plan pricing is increasingly quote-based rather than transparently published$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Citation Builder and managed services add extra cost on top of the core subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Best suited to agencies/multi-location businesses; overkill for a single small local business$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Feature depth (geo-grid tracking, Active Sync) has a learning curve for new users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$What is BrightLocal used for?$q$, $q$BrightLocal is used for local SEO: tracking local search rankings, building and correcting business citations, auditing Google Business Profile listings, and managing customer reviews.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$How much does BrightLocal cost?$q$, $q$Core plans start around $39/month for Track, $49/month for Manage, and $59/month for Grow, billed monthly or annually with an annual discount; managed services and citation building are priced separately.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Does BrightLocal offer a free trial?$q$, $q$Yes, BrightLocal offers a 14-day free trial of its platform with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Who is BrightLocal for?$q$, $q$It's built primarily for SEO and marketing agencies and multi-location businesses that need to manage local search visibility across many locations or clients.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Does BrightLocal offer an API?$q$, $q$Yes, BrightLocal offers Local SEO API access for developers and platforms that want to integrate its citation and ranking data, priced on request.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Agency client reporting$q$, $q$SEO agencies track rankings and citations for dozens of clients and generate white-label reports.$q$, $q$Digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Multi-location listing management$q$, $q$Franchises and multi-location brands keep business information accurate across hundreds of directory listings.$q$, $q$Multi-location and franchise businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Review generation campaigns$q$, $q$Local service businesses automate review request campaigns to build up Google review volume.$q$, $q$Local service businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Track$q$, $q$From $39/month$q$, $q$Monthly or annual (annual discount available)$q$, NULL, $q$["Rank tracking (100 keywords, 4 competitors)","Geo-grid visualization","Citation tracking","Google Business Profile audit"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Manage$q$, $q$From $49/month$q$, $q$Monthly or annual (annual discount available)$q$, NULL, $q$["Everything in Track","AI insights","Active Sync listing management","GBP post scheduler"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$Grow$q$, $q$From $59/month$q$, $q$Monthly or annual (annual discount available)$q$, NULL, $q$["Everything in Manage","Review monitoring","Review collection","Review showcase widget"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BrightLocal was founded in 2008 by Myles Anderson and Ed Eliot in the UK and has grown into one of the longest-running dedicated local SEO platforms, headquartered in Brighton with roughly 170 employees.$q$, $q$The platform serves digital marketing agencies and multi-location brands that need to track local search rankings, keep business listings accurate, and manage customer reviews across many locations at once.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BrightLocal's core toolset spans local rank tracking with geo-grid visualization, citation building and monitoring across business directories, Google Business Profile auditing and post scheduling, and automated review generation and monitoring.$q$, $q$Agencies commonly use BrightLocal for white-label client reporting, while its Citation Builder and managed Local SEO Service give businesses pay-as-you-go or fully done-for-you options beyond the core software subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BrightLocal's core plans are Track (from $39/month), Manage (from $49/month), and Grow (from $59/month), each unlocking more of the platform's citation, listing-management, and review tools, with roughly 25% off for annual billing.$q$, $q$Additional services are priced separately: Citation Builder starts at about $2 per citation pay-as-you-go, the fully managed Local SEO Service starts around $1,299/month, and API access is custom-quoted. A 14-day free trial is available on the core platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05db3079-f16d-4821-84d1-93a68b767ea8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Automated review requests$q$, $q$Send SMS or email review requests automatically after a service or appointment is completed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Multi-platform review monitoring$q$, $q$Monitor and respond to reviews across Google Business Profile, Facebook, TripAdvisor, and Nextdoor.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$AI-assisted web chat$q$, $q$A 24/7 managed website chat widget that engages visitors and captures qualified leads.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Unified messaging inbox$q$, $q$Two-way SMS and email messaging with customers consolidated into a single team inbox.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Mobile payment collection$q$, $q$Accept mobile and online payments from customers directly through the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Vertical software integrations$q$, $q$Connects with QuickBooks, Dentrix, NapaTracs, ServiceMonster, and other trade-specific tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Performance reporting$q$, $q$Dashboards showing review volume, customer interactions, and employee/team performance.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Consolidates reviews, chat, SMS, and payments into one platform, reducing tool sprawl for small businesses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Strong focus on local service verticals with relevant software integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$AI-assisted chat helps capture leads outside business hours$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Backed by Vendasta since its 2023 acquisition, adding resources and stability$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Pricing is not transparent and requires a sales call to obtain a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Payment processing functionality is reported as more limited than dedicated payment tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Pricing scales quickly for multi-location businesses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Primarily built for local/trade businesses, less suited to e-commerce or non-local companies$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$What is Broadly used for?$q$, $q$Broadly is used by local service businesses to generate and manage customer reviews, chat with website visitors, message customers via SMS/email, and collect payments from one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Who owns Broadly?$q$, $q$Broadly was acquired by Vendasta in March 2023 and continues to operate as a distinct customer engagement product.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$How much does Broadly cost?$q$, $q$Broadly does not publish pricing publicly; typical single-location costs are reported around $200-$300 per month, with custom quotes based on locations and features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Does Broadly integrate with other software?$q$, $q$Yes, Broadly integrates with tools like QuickBooks, Dentrix, NapaTracs, and ServiceMonster, among others.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$What size businesses use Broadly?$q$, $q$Broadly is designed primarily for small to mid-sized local, service-based businesses such as home services, dental, and automotive companies.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Automated review generation$q$, $q$A home services company automatically texts customers for reviews after every completed job.$q$, $q$Home services businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$After-hours lead capture$q$, $q$A local business uses AI web chat to engage and qualify website visitors outside business hours.$q$, $q$Local service businesses with website traffic$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$Unified customer communication$q$, $q$Front-desk staff manage SMS, email, and chat conversations with customers from a single inbox.$q$, $q$Multi-staff local businesses$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Broadly was founded in 2013 and is headquartered in San Francisco, California, employing roughly 85 people. In March 2023, Broadly was acquired by Vendasta and continues to operate as a customer engagement platform aimed at local service businesses.$q$, $q$The platform bundles review generation, two-way SMS and web chat, and payment collection into one dashboard, targeting home-services, dental, automotive, and other appointment-driven local businesses that want to reduce the number of separate tools they manage.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Broadly automatically requests reviews via SMS or email after a service is completed and helps publish and monitor those reviews across Google, Facebook, TripAdvisor, and Nextdoor from a single inbox.$q$, $q$Its AI-assisted web chat widget engages website visitors around the clock to capture leads, while unified SMS/email messaging and mobile payment collection round out the customer communication toolkit. Broadly also integrates with vertical tools like QuickBooks, Dentrix, NapaTracs, and ServiceMonster.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Broadly does not publish list pricing; prospective customers must request a custom quote. Third-party sources report typical starting costs in the roughly $200-$300 per month range for a single location, with pricing scaling based on the number of locations and features enabled.$q$, $q$Annual prepayment can reduce the effective monthly cost, and enterprise/multi-location pricing is quoted individually.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6724785a-7009-4bc5-a8a9-4314ca7e5d4f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Real device cloud$q$, $q$Instant access to thousands of real mobile devices and desktop browser/OS combinations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Automated testing (Automate)$q$, $q$Run Selenium, Cypress, Playwright, and other automated test suites against the cloud device grid.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Native app testing$q$, $q$App Live and App Automate support manual and automated testing of native iOS and Android apps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Visual regression testing$q$, $q$Percy detects unintended visual changes across browsers and screen sizes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$CI/CD integrations$q$, $q$Plugs into Jenkins, CircleCI, GitHub Actions, GitLab CI, and other pipelines for continuous testing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Test observability$q$, $q$Debugging and analytics tools that help teams diagnose flaky tests and failures faster.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Extremely broad inventory of real browsers and mobile devices, avoiding the need for an in-house device lab$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Deep integrations with CI/CD pipelines and popular test automation frameworks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Trusted by large enterprises with strong uptime and security/compliance credentials$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Separate product tiers let teams pay only for the testing types they need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Costs can add up quickly for teams needing multiple products (Automate, App Automate, Percy) simultaneously$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Enterprise-grade pricing is not transparent and requires a custom quote$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Parallel test session limits on lower tiers can slow down large test suites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Learning curve for teams new to cloud-based test automation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$What is BrowserStack used for?$q$, $q$BrowserStack is used to test web and mobile applications across real browsers, real devices, and operating systems in the cloud, both manually and via automated test suites.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$How much does BrowserStack cost?$q$, $q$Plans start at $29/month (Live, annual billing) and scale up to $199-$249/month for App Automate, with custom enterprise pricing for larger teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Does BrowserStack offer a free trial?$q$, $q$Yes, BrowserStack offers a free trial across its core testing products.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Can BrowserStack test native mobile apps?$q$, $q$Yes, App Live and App Automate support manual and automated testing of native iOS and Android apps on real devices.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Does BrowserStack integrate with CI/CD tools?$q$, $q$Yes, it integrates with Jenkins, CircleCI, GitHub Actions, GitLab CI, and major test automation frameworks.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Cross-browser compatibility testing$q$, $q$QA teams verify a web app renders and functions correctly across dozens of browser/OS combinations.$q$, $q$QA and web engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Mobile app release testing$q$, $q$Mobile teams run automated and manual tests on real iOS and Android devices before shipping releases.$q$, $q$Mobile app development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Continuous testing in CI/CD$q$, $q$Engineering teams run automated test suites against the BrowserStack cloud grid on every pull request.$q$, $q$DevOps and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Live$q$, $q$$29/month (annual) / $39/month$q$, $q$Monthly or annual$q$, NULL, $q$["Real desktop browser testing","Manual interactive testing","Cross-browser debugging tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$Desktop & Mobile$q$, $q$From ~$39/month (annual) / $49/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Live","Real mobile device testing","Mobile developer tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$App Automate$q$, $q$From ~$199/month (annual) / $249/month$q$, $q$Monthly or annual$q$, NULL, $q$["Automated native app testing","Real device cloud for iOS/Android","CI/CD integration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BrowserStack was founded in 2011 by Ritesh Arora and Nakul Aggarwal and is headquartered in Mumbai, India, with offices in Dublin, San Francisco, New York, and Vancouver. The company employs roughly 1,800 people and serves over 50,000 paying customers worldwide.$q$, $q$BrowserStack provides cloud access to real browsers, real mobile devices, and emulators so engineering and QA teams can test web and mobile applications without maintaining physical device labs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core products include Live for manual interactive testing, Automate for running automated test suites (Selenium, Cypress, Playwright) against the cloud grid, App Live and App Automate for native iOS and Android app testing on real devices, and Percy for visual regression testing.$q$, $q$The platform integrates with major CI/CD tools, test frameworks, and issue trackers, and includes AI-assisted testing and test-observability features for modern engineering workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BrowserStack prices its products separately: Live starts at $29/month (annual billing), Desktop & Mobile starts around $39/month annual, and App Automate starts around $199/month annual, with higher monthly rates for non-annual billing.$q$, $q$Enterprise plans with custom device access and dedicated support are quoted individually, commonly ranging from about $12,000 to $40,000 per year. A free trial is available on core products.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('509b81fc-5715-4f19-a1df-3b3b13c8ed42', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Git-native collection storage$q$, $q$API collections are saved as plain-text files, enabling version control with standard Git workflows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Multi-protocol support$q$, $q$Test REST, GraphQL, gRPC, WebSocket, Server-Sent Events, Socket.IO, and MQTT from one client.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Offline, local-first design$q$, $q$No mandatory cloud account; API data stays on the developer's machine by default.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Scripting and environments$q$, $q$Pre-request/post-response scripting and environment variables for dynamic API testing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Cross-platform desktop app$q$, $q$Native builds for macOS, Windows, and Linux, plus a VS Code/Open VSX extension.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Open-source core$q$, $q$The majority of Bruno's features are free and open source, inspectable on GitHub.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Free and open source with a fast-growing GitHub community (40,000+ stars)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Git-native storage keeps API collections versioned alongside application code$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Strong privacy stance: no forced cloud account or data upload for core features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Broad protocol support including gRPC and WebSockets, not just REST$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$No built-in cloud sync, which can add friction for distributed teams without shared Git access$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Team collaboration features beyond Git are a separate paid offering with less publicized pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Smaller plugin/integration ecosystem compared to long-established tools like Postman$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$UI and feature set still maturing relative to more established commercial API clients$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Is Bruno free to use?$q$, $q$Yes, the core Bruno application and most of its protocol support (REST, GraphQL, gRPC, WebSocket) are free and open source.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$What makes Bruno different from Postman?$q$, $q$Bruno stores API collections as local plain-text files that work naturally with Git, rather than syncing them to a proprietary cloud account, giving developers more control over their data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Does Bruno support gRPC and WebSockets?$q$, $q$Yes, Bruno supports gRPC (including streaming calls), WebSockets, Server-Sent Events, and additional protocols like Socket.IO and MQTT.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Is Bruno open source?$q$, $q$Yes, Bruno is open source, with its source code available on GitHub under the usebruno/bruno repository.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Does Bruno offer cloud sync?$q$, $q$No, Bruno intentionally does not offer cloud sync for the core product, prioritizing local, offline-first data storage.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$API development and testing$q$, $q$Developers build and test REST and GraphQL requests during backend development.$q$, $q$Backend and full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Version-controlled API collections$q$, $q$Teams store API collections in the same Git repository as their code for review and CI integration.$q$, $q$Engineering teams using Git workflows$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$Privacy-conscious API testing$q$, $q$Developers who need to keep API request data off third-party servers use Bruno's local-first model.$q$, $q$Security-conscious developers and teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bruno is an open-source API client created by developer Anoop M. D. and launched around 2021-2022 as a lightweight, privacy-focused alternative to Postman and Insomnia.$q$, $q$Its core differentiator is storing API collections as plain-text files on the local filesystem, so developers can manage and version them with ordinary Git workflows instead of syncing to a proprietary cloud.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bruno supports REST, GraphQL (with schema introspection), gRPC (including streaming calls), WebSockets, Server-Sent Events, Socket.IO, and MQTT, all through a native desktop app for macOS, Windows, and Linux.$q$, $q$Collections are stored in a plain-text Bru format that plays well with Git-based code review and CI pipelines, and the project has grown to over 40,000 GitHub stars since launch.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Bruno application and the majority of its protocol support and scripting features are free and open source. Paid team-collaboration features exist as a separate commercial offering for organizations that want managed collection sharing beyond plain Git access.$q$, $q$There is no cloud-sync add-on for the free product, since the Bruno team has stated it intentionally avoids building cloud storage for user API data.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27d9c1d-671b-4574-89ec-95d7edf9ea00', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Visual app builder$q$, $q$Drag-and-drop editor for building front-end UI without writing HTML/CSS/JS.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Built-in database$q$, $q$A relational database included natively for storing and querying application data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Visual workflow engine$q$, $q$Define backend logic, automations, and API calls through visual workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Plugin marketplace$q$, $q$Thousands of official and community plugins for payments, email, analytics, and integrations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$AI-assisted building$q$, $q$AI tools that help generate and edit app structure and workflows within the builder.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Responsive design tools$q$, $q$Build layouts that adapt across desktop and mobile screen sizes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Custom code and API connectors$q$, $q$Extend apps with custom code, external APIs, and plugin development for advanced use cases.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Full-stack capability (database + backend logic + UI) rather than just a website builder$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Large plugin ecosystem covering payments, integrations, and add-on functionality$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Free plan available for learning and prototyping before committing to a paid tier$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Extensible with custom code and APIs for teams that outgrow pure no-code$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Workload Unit pricing can be difficult to predict and may scale quickly for high-traffic apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Steeper learning curve than simpler website builders due to its full-stack complexity$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Performance can be a concern for very large-scale or highly data-intensive applications$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Migrating off Bubble is nontrivial since apps are tied to its proprietary runtime$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$What is Bubble used for?$q$, $q$Bubble is used to build full-stack web and mobile-responsive applications — including databases and backend logic — visually, without writing traditional code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$How much does Bubble cost?$q$, $q$Bubble has a free plan for prototyping, with paid plans starting at $29/month (Starter), $119/month (Growth), and $349/month (Team), priced using a Workload Unit system.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Is Bubble a true no-code platform?$q$, $q$Yes, Bubble is a no-code platform, though it also supports custom code, API connectors, and plugins for teams that want more control or advanced functionality.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Who founded Bubble?$q$, $q$Bubble was founded in 2012 by Emmanuel Straschnov and Josh Haas, who remain co-CEOs of the company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Does Bubble support mobile apps?$q$, $q$Bubble builds responsive web apps that work well on mobile browsers; native mobile app packaging is possible through third-party tools and Bubble's own mobile app features.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$MVP and startup app development$q$, $q$Non-technical founders build and launch a functional SaaS or marketplace MVP without hiring engineers.$q$, $q$Startup founders and small teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Internal tools and dashboards$q$, $q$Operations teams build internal tools and admin dashboards connected to their business data.$q$, $q$Internal operations and business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Agency client app development$q$, $q$No-code agencies build custom web applications for clients faster than traditional development.$q$, $q$No-code development agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["50,000 Workload Units/month","Learning and prototyping","No live app deployment or team collaboration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Starter$q$, $q$$29/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["175,000 Workload Units/month","Custom domain and SSL","Removes Bubble branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Growth$q$, $q$$119/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["250,000 Workload Units/month","Premium version control","Two-factor authentication","Two app editors, ten custom branches"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$Team$q$, $q$$349/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["500,000 Workload Units/month","Up to 5 app editors","1 TB of storage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bubble was founded in 2012 by Emmanuel Straschnov and Josh Haas and is headquartered in New York City, with roughly 500 employees and over $100 million in venture funding raised.$q$, $q$The platform lets users visually build full-stack web applications — including the database, backend logic, and front-end UI — without writing traditional code, while still supporting custom code, APIs, and plugins for advanced use cases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bubble includes a built-in relational database, a visual workflow engine for backend logic and automations, responsive UI design tools, user authentication, and a large plugin marketplace for payments, email, and third-party integrations.$q$, $q$The platform has added AI-assisted app building tools and, following its 2024 acquisition of Flusk, includes stronger native security and monitoring capabilities for apps built on Bubble.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Since 2023, Bubble prices paid plans using Workload Units (WUs), which measure database queries, workflow runs, and API calls. The Free plan includes 50,000 WUs/month for prototyping.$q$, $q$Paid plans are Starter ($29/month, 175,000 WUs), Growth ($119/month, 250,000 WUs), and Team ($349/month, 500,000 WUs, up to 5 app editors), with usage-based scaling for larger production apps.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
