INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdbd18ff-a281-4cb1-87dc-90ab666683fe', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Visual pipeline editor$q$, $q$Drag-and-drop pipeline builder assembled from 150+ pre-built actions, no YAML required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Multi-cloud deployment$q$, $q$Automated deployment to AWS, Google Cloud, Microsoft Azure, DigitalOcean, and FTP/SFTP servers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Kubernetes and Docker support$q$, $q$Native Docker-based pipelines and Kubernetes deployment actions for containerized apps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Git provider integrations$q$, $q$Connects to GitHub, GitLab, Bitbucket, and private/self-hosted repositories.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Flexible pipeline triggers$q$, $q$Trigger pipelines from Git events, AWS, Slack, or external servers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$SOC 2 Type II security$q$, $q$Independently audited security controls covering availability and confidentiality.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$SSO and advanced permissions$q$, $q$SAML/OIDC single sign-on and granular pipeline/user/group permissions on higher tiers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Visual pipeline editor lowers the barrier to CI/CD setup compared to YAML-first tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Functional, uncapped-duration free tier for small projects and evaluation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Broad cloud and Kubernetes deployment support out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$SOC 2 Type II certified with an on-premises option for compliance-sensitive teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Usage-based pricing (pipeline GB-minutes, cache, seats) can be harder to predict than flat per-seat pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Smaller ecosystem and community compared to GitHub Actions or GitLab CI$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Advanced enterprise features (SSO, advanced permissions) are gated to the higher Hyper tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Visual builder may feel less flexible than pure code-based pipelines for complex custom logic$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$What is Buddy used for?$q$, $q$Buddy is used for CI/CD automation — building, testing, and deploying applications through a visual pipeline editor connected to Git repositories and cloud providers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$How much does Buddy cost?$q$, $q$Buddy has a free plan for small projects, with paid plans starting at €29/month (Pro) and €99/month (Hyper), plus metered overages for extra usage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Does Buddy require writing YAML?$q$, $q$No, Buddy's core feature is a visual drag-and-drop pipeline editor, though it also supports YAML-based pipeline definitions for teams that prefer them.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Can Buddy deploy to Kubernetes?$q$, $q$Yes, Buddy includes native Kubernetes deployment actions and integrates with tools like AWS CodeDeploy.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Is Buddy self-hosted?$q$, $q$Buddy is primarily a cloud service, but it also offers an on-premises deployment option starting around $35/month for organizations that need self-hosting.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Visual CI/CD for small teams$q$, $q$A small dev team automates build, test, and deploy steps without needing a dedicated DevOps engineer to write YAML.$q$, $q$Small to mid-sized development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Containerized app deployment$q$, $q$A team builds Docker images and deploys them to Kubernetes clusters through Buddy's visual pipelines.$q$, $q$DevOps and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Multi-cloud deployment automation$q$, $q$An agency automates deployments across AWS, DigitalOcean, and FTP hosting for different client projects.$q$, $q$Agencies managing multiple client deployments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Free$q$, $q$€0$q$, $q$N/A$q$, NULL, $q$["1 seat","1 concurrent pipeline","300 pipeline GB-minutes","1 GB pipeline cache"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Pro$q$, $q$€29/month$q$, $q$Monthly$q$, NULL, $q$["2 seats","1 concurrent pipeline","3,000 pipeline GB-minutes","10 GB pipeline cache"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$Hyper$q$, $q$€99/month$q$, $q$Monthly$q$, NULL, $q$["5 seats","2 concurrent pipelines","6,000 pipeline GB-minutes","SSO (SAML & OIDC)","Advanced permissions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Buddy is a CI/CD automation platform founded in 2015 by Simon Szczepankowski and Raph Sztwiorok, operated by BDY PSA and headquartered in Warsaw, Poland, with an estimated 11-50 employees.$q$, $q$Its defining feature is a visual, drag-and-drop pipeline editor built from over 150 pre-built actions, letting teams automate builds, tests, and deployments without hand-writing YAML, while still supporting YAML-based pipelines for teams that prefer them.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Buddy integrates with GitHub, GitLab, and Bitbucket, and deploys to FTP/SFTP, AWS, Google Cloud, Microsoft Azure, and DigitalOcean, with native Kubernetes deployment actions for containerized infrastructure.$q$, $q$The platform is Docker-based, supports pipeline triggers from Git, AWS, Slack, and other sources, and holds SOC 2 Type II certification for security-conscious teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Buddy offers a functional Free plan (1 seat, 300 pipeline GB-minutes, 1 GB cache) with no time limit, alongside usage-based paid plans: Pro at €29/month and Hyper at €99/month, with additional seats and resources available as metered add-ons.$q$, $q$An on-premises/self-hosted option is also available for organizations with compliance or data residency requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a8f6b931-ead8-4549-9325-5d2d323f59c8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Extended member profiles$q$, $q$Customizable user profile fields beyond WordPress's default user data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Activity streams$q$, $q$A social news feed showing member posts, updates, and site activity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Groups$q$, $q$Public, private, or hidden groups members can create and join around shared interests.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Private messaging$q$, $q$Direct messaging between members within the site.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Friend connections$q$, $q$Member-to-member connection/friend request system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Notifications$q$, $q$In-site notifications for activity, messages, and group updates.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Self-hosted, giving site owners full control and ownership of community data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Deep integration with the WordPress ecosystem, themes, and plugins$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Long track record and active volunteer maintenance since 2008$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Requires a self-managed WordPress installation and hosting, adding technical overhead versus hosted community platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Default design is basic and typically needs a dedicated theme (e.g. BuddyX) for a polished look$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Feature depth for large-scale communities often requires premium add-ons or the commercial BuddyBoss fork$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Community/volunteer-driven development can mean slower feature releases than VC-backed competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Is BuddyPress free?$q$, $q$Yes, BuddyPress is completely free and open source. Only WordPress hosting and any optional premium themes or extensions cost money.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$What does BuddyPress do?$q$, $q$BuddyPress turns a WordPress site into a social network, adding member profiles, activity feeds, groups, private messaging, and friend connections.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Who maintains BuddyPress?$q$, $q$BuddyPress is maintained by a team of volunteer contributors under the WordPress Foundation, after Automattic transferred ownership to the foundation in 2010.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Do I need a special theme for BuddyPress?$q$, $q$Not strictly, but community-oriented themes like BuddyX or Reign are commonly used to give BuddyPress sites a more polished, purpose-built design.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$How is BuddyPress different from BuddyBoss?$q$, $q$BuddyBoss is a commercial platform built on top of BuddyPress that adds premium features, support, and a dedicated app builder, while BuddyPress itself remains free and open source.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Membership community sites$q$, $q$Organizations run a self-hosted community with profiles, groups, and discussions instead of using a third-party platform.$q$, $q$Membership organizations and associations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$School and university communities$q$, $q$Educational institutions build private social networks for students, alumni, or staff.$q$, $q$Schools and universities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$Interest-based hobby communities$q$, $q$Hobbyist groups or clubs build a branded community site with groups and activity feeds.$q$, $q$Hobby groups, clubs, and niche communities$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BuddyPress was conceived in 2007-2008 by developer Andy Peatling, who was acqui-hired by Automattic in March 2008 to develop it full time; the first 1.0 release shipped in April 2009. In 2010, Automattic transferred ownership to the nonprofit WordPress Foundation, placing BuddyPress under community stewardship.$q$, $q$The plugin turns a WordPress site or Multisite network into a full social networking platform, and remains actively maintained by volunteer contributors with regular releases through 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BuddyPress adds extended member profiles, activity streams, user groups, private messaging, friend connections, and notifications as a modular set of components site owners can individually enable.$q$, $q$Being built on WordPress, it benefits from the broader plugin and theme ecosystem, and is commonly paired with community-focused themes like BuddyX or Reign, and with bbPress for discussion forums.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bcf631f-554c-4a18-befe-b606018906d6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BuddyPress itself is completely free and open source, with no licensing cost to download or use on any WordPress site.$q$, $q$Site owners still bear the cost of WordPress hosting and any optional premium themes or third-party extensions they choose to add on top of BuddyPress.$q$]::text[], 2);
