-- ── Broadly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Broadly is an AI-powered customer engagement platform for local service businesses, combining review generation, web chat, SMS, and payments.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (typically $200+/month)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$~85 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Broadly Review 2026: Pricing, Features & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Broadly is a reputation management and customer engagement platform for local businesses. See pricing, features, and how its review, chat, and SMS tools work.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Broadly is a customer engagement and online reputation management platform for local, service-based businesses, founded in 2013 and headquartered in San Francisco, California, with roughly 85 employees. Broadly was acquired by Vendasta in March 2023, which continues to operate it as a distinct product aimed at small and mid-sized local service companies such as home services, dental, automotive, and other appointment-driven businesses. The platform positions itself as an all-in-one tool that consolidates review generation, two-way SMS and web chat messaging, and payment collection into a single interface, reducing the number of separate point solutions a small business needs to manage customer relationships. Its core review-generation feature automatically sends SMS or email requests to customers after a service is completed, then helps publish and manage the resulting reviews across Google Business Profile, Facebook, TripAdvisor, and Nextdoor, alongside monitoring and response tools that let owners answer feedback from one dashboard. The web chat product adds an AI-assisted, 24/7 managed website chat widget that engages visitors, captures lead details, and can route qualified leads to the sales team, positioning Broadly as an AI-driven lead-capture platform in its own marketing (broadly.com describes itself as an 'AI Platform for Reviews & Leads'). Two-way SMS and email messaging are unified into a shared inbox so staff can text and email customers, request reviews, and answer questions without switching tools. Broadly also offers mobile and online payment collection, though third-party reviews note more limited payment functionality compared to dedicated payment processors. The platform integrates with a number of vertical-specific business tools including QuickBooks, Dentrix (dental practice management), NapaTracs (auto repair), and ServiceMonster (home services), reflecting its focus on trade and local-service verticals. Reporting tools give managers visibility into review volume, customer interactions, and employee performance. Pricing is not publicly published; third-party sources report typical single-location pricing in the range of roughly $200-$300 per month, scaling with the number of business locations and the mix of features (review generation, chat, payments) selected, with custom quotes required for most prospective customers and periodic discounts for annual prepayment. Broadly's primary competitors include Birdeye, Podium, and Vendasta's own broader marketing suite; it differentiates through its narrower focus on local trade and service businesses and its bundled chat-plus-reviews-plus-payments approach.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6724785a-7009-4bc5-a8a9-4314ca7e5d4f';

