-- ── Bruno ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bruno is an open-source, git-native API client for REST, GraphQL, gRPC, and WebSockets that stores collections as local plain-text files.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Bangalore, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bruno Review 2026: Open-Source Git-Native API Client$q$, seo_title),
  seo_meta_description = COALESCE($q$Bruno is a free, open-source API client that stores collections as local files for Git version control. See features, pricing, and how it compares to Postman.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bruno is an open-source API client created by Anoop M. D., a developer based in Bangalore, India, launched in 2021-2022 as a lightweight, local-first alternative to Postman and Insomnia. Its defining architectural decision is being 'git-native': instead of syncing API collections to a proprietary cloud, Bruno stores each collection as plain-text files on the local filesystem using a custom markup format called Bru, so developers can version-control their API requests, environments, and test scripts using ordinary Git workflows alongside their application code. This design directly addresses privacy and vendor-lock-in concerns that emerged after Postman shifted toward mandatory cloud accounts and cloud-synced collections. Bruno supports REST, GraphQL (including query execution and schema introspection), gRPC (unary, server-streaming, client-streaming, and bidirectional streaming calls), WebSockets, Server-Sent Events, and additional protocols like Socket.IO and MQTT. It ships as a native desktop application for macOS, Windows, and Linux, and is also available as a VS Code / Open VSX extension. The project grew quickly in the open-source community, surpassing 40,000 GitHub stars within roughly two years of launch, making it one of the fastest-growing developer tools in the API-testing category. The majority of Bruno's functionality — request building, collection management, environment variables, scripting, and protocol support (GraphQL, gRPC, WebSocket, MQTT) — is free and open source under its published license, reflecting the maintainers' stated goal of balancing open-source principles with long-term project sustainability. Bruno additionally offers paid features aimed at teams, generally bundled as a separate commercial/cloud tier for collaboration features that go beyond what Git-based sharing alone provides (such as team collection sharing without requiring every member to manage Git access directly); pricing for these team features is not uniformly published and is best confirmed on Bruno's official site. Because Bruno explicitly avoids building a cloud-sync backend for the core product — the team has stated no plans to add cloud sync, citing a commitment to keeping user data on-device — it is positioned primarily for individual developers and small teams who already use Git and want their API collections to live alongside their source code rather than in a third-party SaaS account. Typical use cases include testing REST and GraphQL APIs during development, keeping API test collections in the same repository as backend code for code review and CI, and evaluating gRPC/WebSocket services without needing a heavier, cloud-dependent tool. Its main competitors are Postman, Insomnia, and Hoppscotch, with Bruno differentiating primarily on its local-first, Git-native storage model and open-source licensing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a27d9c1d-671b-4574-89ec-95d7edf9ea00';

