  short_description = COALESCE($q$Buddy is a CI/CD automation platform with a visual pipeline editor for building, testing, and deploying applications without writing YAML.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from €29/month)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
