-- ── BuddyPress ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BuddyPress is a free, open-source WordPress plugin that turns any WordPress site into a full social network with profiles, groups, and activity feeds.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Open-source community project (originally backed by Automattic)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BuddyPress Review 2026: Free WordPress Social Network Plugin$q$, seo_title),
  seo_meta_description = COALESCE($q$BuddyPress is a free, open-source WordPress plugin for building social networks with profiles, groups, and activity feeds. See features and how it works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BuddyPress is a free, open-source social networking plugin for WordPress, conceived in 2007-2008 by developer Andy Peatling. Peatling was acqui-hired by Automattic in March 2008, which took the project under its wing and employed him to develop it full time; the first public beta was released in December 2008, followed by version 1.0 in April 2009. In 2010, Automattic transferred ownership and control of BuddyPress, along with bbPress, to the nonprofit WordPress Foundation, effectively placing the project under community stewardship rather than corporate ownership, similar to WordPress core itself. BuddyPress transforms a standard WordPress installation (or WordPress Multisite network) into a full social networking platform, adding extended member profiles, activity streams/news feeds, user groups and communities, private messaging between members, friend/connection systems, and notifications — the standard feature set expected of a social network, built as a modular suite of components that site owners can enable or disable individually. Because it is a WordPress plugin, BuddyPress is written in PHP and MySQL and benefits from the entire WordPress plugin and theme ecosystem, allowing it to be extended with add-ons for functionality like private communities, media sharing, forums (often paired with bbPress), and e-commerce. It is commonly paired with community-oriented themes such as BuddyX and Reign to provide a polished, responsive front-end. As of 2026, BuddyPress remains actively maintained by a team of volunteer contributors, with maintenance and security releases continuing on a regular cadence (for example, version 14.x releases through 2024-2025) and an active documentation and support community coordinated through WordPress.org's plugin repository and dedicated community meetings. Being fully free and open source, BuddyPress has no licensing cost — the plugin itself is free to download and use on any WordPress site, though hosting, a WordPress installation, and any premium themes or extensions a site owner chooses are separate costs borne by the site operator (BuddyPress itself does not host anything or process payments). BuddyPress is primarily used by schools, universities, membership organizations, companies building internal communities, hobbyist and interest-based communities, and sports teams or clubs that want to run their own self-hosted social network rather than build a community on a third-party platform like Facebook Groups or Discord. Its main competitors in the WordPress social-networking space include BuddyBoss (a commercial fork/enhancement built on BuddyPress) and PeepSo, a newer alternative that emerged roughly seven years after BuddyPress launched.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9bcf631f-554c-4a18-befe-b606018906d6';

